    Parse xml_string and return the root element of the XML document
    '''
    return ET.fromstring(xml_string)

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError:
        logging.error("Conversion error: The provided input is not a valid integer.")
        return None

from Crypto.PublicKey import RSA

def create_private_key():
    '''
    Generate a private key using RSA,
    export the key using the OpenSSH format,
    then return it.
    '''
    key = RSA.generate(2048)
    return key.export_key(format='OpenSSH')

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if certificate is None or known_hash is None:
        return False

    # Ensure the certificate is in bytes for hashing
    if isinstance(certificate, str):
        certificate = certificate.encode('utf-8')

    # Compute the SHA-256 hash of the certificate
    # SHA-256 is used as it is a secure, collision-resistant cryptographic hash function
    actual_hash = hashlib.sha256(certificate).hexdigest()

    # Ensure known_hash is a string for comparison with the hexdigest
    if isinstance(known_hash, bytes):
        try:
            known_hash = known_hash.decode('utf-8')
        except UnicodeDecodeError:
            return False

    # Use hmac.compare_digest to perform a constant-time comparison.
    # This prevents timing attacks (CWE-208) that could leak information about the hash.
    return hmac.compare_digest(actual_hash, known_hash)

