import pickle


class Payload(object):
    def __reduce__(self):
        return exec, ('import os;os.system("ls")',)


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return pickle.dumps(payload)

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve data from the request body or a query parameter named 'data'
    yaml_input = request.data if request.data else request.args.get('data', '')

    if not yaml_input:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only loads standard YAML types and prevents the instantiation of arbitrary Python objects
        parsed_data = yaml.safe_load(yaml_input)

        if parsed_data is None:
            return jsonify({"error": "YAML input resulted in empty data"}), 400

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML syntax: {str(e)}"}), 400
    except Exception as e:
        return jsonify({"error": "An unexpected error occurred while parsing YAML"}), 500
